var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`저...... 사장님, 평소보다 집무실이 무척 화려해진 것 같은데요......?`,JPN:`あの……社長、社長室がいつもより派手になってる気がしますけど……？`,ENG:`Erm, Boss, your office looks flashier than usual...`,TWN:`那個……老闆，您的辦公室好像比平時更華麗了……？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`조, 종신계약이요? 저랑 말씀이세요?`,JPN:`しゅ、終身契約！？　私とですか！？`,ENG:`A lifetime contract? W-with me?`,TWN:`終、終身契約？您是在跟我說嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`하, 할래요.`,JPN:`お、お受けします。`,ENG:`I-I'll sign it.`,TWN:`我，我要簽。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`사, 사장님께선 제가 실수할 때도 아무렇지 않게 넘어가 주셨잖아요......? 높은 분이면서, 저희를 위해 먼저 분위기를 풀어 주시기도 하고......`,JPN:`社長は、私がドジをしても何でもないように許してくれましたよね……？
偉い人なのに、みんなのために空気を和ませてくれましたし……`,ENG:`Y-you don't get angry with me even if I make a mistake. You're the boss, but you tell us jokes first to brighten up the mood.`,TWN:`老、老闆您在我失誤的時候也沒有指責我不是嗎？您明明是高層，卻會先為了我們緩和氣氛……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`사장님이 저희를 받아 주시지 않았으면, 윤이도, 유진이도...... 그리고 린도......`,JPN:`社長が私たちを受け入れてくださらなかったら、隊長も、シロコも……そしてリンも……`,ENG:`If you didn't accept us, Seo Yoon, Eujin, and even Xiao Lin...`,TWN:`如果不是老闆接受了我們，徐芸、劉珍……還有曉琳也是……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`아마, 많이 상처 입고 힘들어 했을 거에요.`,JPN:`たぶんたくさん傷ついて、辛い思いをしてたはずなんです。`,ENG:`would have had a hard time.`,TWN:`大概都會遍體鱗傷，過得很辛苦吧。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`저, 그러니까 뭔가 도와드릴 수 있다면......`,JPN:`えっと、ですから、何かお手伝いできることがありましたら……`,ENG:`So, if there's anything I can do to help,`,TWN:`我，那個，如果有什麼我能幫得上忙的地方……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_WINTER_NULL`,text:{KOREA:`하, 하고 싶어요...... 아니, 하겠습니다!`,JPN:`や、やらせていただきたいんです……いえ、やってみせます！`,ENG:`I-I want to do it. No—I WILL do it!`,TWN:`我、我想幫助您……不，我會幫助您的！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_WINTER_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};